"""
Machine Learning Algorithms Implementation
"""

import numpy as np
import pandas as pd
from typing import List, Tuple, Any, Optional, Union
from scipy import stats


class FindS:
    """
    Find-S Algorithm implementation for concept learning.
    Finds the most specific hypothesis consistent with positive training examples.
    """
    
    def __init__(self):
        self.hypothesis = None
        self.is_fitted = False
    
    def fit(self, X: Union[np.ndarray, pd.DataFrame], y: Union[np.ndarray, pd.Series]) -> List:
        """
        Fit the Find-S algorithm to training data.
        
        Args:
            X: Feature matrix (dataframe or numpy array)
            y: Target labels (series or numpy array)
        
        Returns:
            List representing the most specific hypothesis
        """
        # Convert to numpy if pandas objects
        if isinstance(X, pd.DataFrame):
            X = X.values
        if isinstance(y, pd.Series):
            y = y.values
        
        # Get shape info
        n_samples, n_features = X.shape
        
        # Initialize hypothesis with all '?' (most general specific hypothesis)
        self.hypothesis = ['?' for _ in range(n_features)]
        
        # Iterate through positive examples only
        for i in range(n_samples):
            if y[i] == 1 or y[i] == 'Yes' or y[i] == 'Positive':  # Positive example
                for j in range(n_features):
                    if self.hypothesis[j] == '?':
                        # First positive example - make it specific
                        self.hypothesis[j] = X[i][j]
                    elif self.hypothesis[j] != X[i][j]:
                        # Generalize to '?' if there's a conflict
                        self.hypothesis[j] = '?'
        
        self.is_fitted = True
        return self.hypothesis
    
    def predict(self, X: Union[np.ndarray, pd.DataFrame]) -> List[bool]:
        """
        Predict labels for given data using the learned hypothesis.
        
        Args:
            X: Feature matrix to predict
        
        Returns:
            List of boolean predictions
        """
        if not self.is_fitted:
            raise ValueError("Model must be fitted before prediction")
        
        # Convert to numpy if pandas objects
        if isinstance(X, pd.DataFrame):
            X = X.values
        
        predictions = []
        for sample in X:
            match = True
            for i, val in enumerate(sample):
                if self.hypothesis[i] != '?' and self.hypothesis[i] != val:
                    match = False
                    break
            predictions.append(match)
        
        return predictions


class CandidateElimination:
    """
    Candidate Elimination Algorithm implementation.
    Finds the version space - the set of all hypotheses consistent with the training examples.
    """
    
    def __init__(self):
        self.general_boundary = []
        self.specific_boundary = []
        self.all_hypotheses = []
    
    def fit(self, X: Union[np.ndarray, pd.DataFrame], y: Union[np.ndarray, pd.Series]) -> Tuple[List, List, List]:
        """
        Fit the Candidate Elimination algorithm to training data.
        
        Args:
            X: Feature matrix
            y: Target labels
        
        Returns:
            Tuple of (general_boundary, specific_boundary, all_hypotheses)
        """
        # Convert to numpy if pandas objects
        if isinstance(X, pd.DataFrame):
            X = X.values
        if isinstance(y, pd.Series):
            y = y.values
        
        n_samples, n_features = X.shape
        
        # Initialize most general boundary
        general = [tuple(['?' for _ in range(n_features)])]
        
        # Initialize most specific boundary
        specific = [tuple(['<' for _ in range(n_features)])]  # '<' means phi (empty)
        
        # Process each training example
        for i in range(n_samples):
            is_positive = (y[i] == 1 or y[i] == 'Yes' or y[i] == 'Positive')
            
            if is_positive:
                # Remove inconsistent hypotheses from general boundary
                general = [h for h in general if self._consistent(X[i], h, True)]
                
                # Minimize specific boundary
                specific_new = []
                for s in specific:
                    if self._consistent(X[i], s, True):
                        specific_new.append(s)
                    else:
                        # Find minimal generalizations of s
                        for g in self._minimal_generalizations(s, X[i]):
                            if self._more_general_than_any(g, specific) and \
                               not self._more_specific_than_any(g, general):
                                specific_new.append(g)
                specific = self._remove_duplicates(specific_new)
                
            else:  # Negative example
                # Remove inconsistent hypotheses from specific boundary
                specific = [h for h in specific if self._consistent(X[i], h, False)]
                
                # Minimize general boundary
                general_new = []
                for g in general:
                    if self._consistent(X[i], g, False):
                        general_new.append(g)
                    else:
                        # Find minimal specializations of g
                        for s in self._minimal_specializations(g, X[i]):
                            if self._more_specific_than_any(s, specific) and \
                               not self._more_general_than_any(s, general):
                                general_new.append(s)
                general = self._remove_duplicates(general_new)
        
        self.general_boundary = general
        self.specific_boundary = specific
        
        # Generate all hypotheses in the version space
        self.all_hypotheses = self._generate_version_space(general, specific, n_features)
        
        return self.general_boundary, self.specific_boundary, self.all_hypotheses
    
    def _consistent(self, example, hypothesis, is_positive):
        """Check if hypothesis is consistent with example"""
        for i, val in enumerate(example):
            if hypothesis[i] == '?':
                continue
            if hypothesis[i] != val:
                return not is_positive
        return is_positive
    
    def _more_general_than_any(self, h, hypotheses):
        """Check if h is more general than any hypothesis in the list"""
        for hyp in hypotheses:
            if self._more_general_than(h, hyp):
                return True
        return False
    
    def _more_specific_than_any(self, h, hypotheses):
        """Check if h is more specific than any hypothesis in the list"""
        for hyp in hypotheses:
            if self._more_specific_than(h, hyp):
                return True
        return False
    
    def _more_general_than(self, h1, h2):
        """Check if h1 is more general than h2"""
        for i in range(len(h1)):
            if h1[i] != '?' and h1[i] != h2[i]:
                return False
        return h1 != h2
    
    def _more_specific_than(self, h1, h2):
        """Check if h1 is more specific than h2"""
        for i in range(len(h1)):
            if h2[i] == '?':
                if h1[i] != '?':
                    return False
            elif h1[i] != h2[i] and h1[i] != '?':
                return False
        return h1 != h2
    
    def _minimal_generalizations(self, h, x):
        """Generate minimal generalizations of h that cover x"""
        generalizations = []
        h_list = list(h)
        for i in range(len(h_list)):
            if h_list[i] == '<':
                generalizations.append(tuple(h_list[:i] + [x[i]] + h_list[i+1:]))
            elif h_list[i] != x[i]:
                generalizations.append(tuple(h_list[:i] + ['?'] + h_list[i+1:]))
        return generalizations if generalizations else [tuple(['?' for _ in range(len(h_list))])]
    
    def _minimal_specializations(self, h, x):
        """Generate minimal specializations of h that do not cover x"""
        specializations = []
        h_list = list(h)
        for i in range(len(h_list)):
            if h_list[i] == '?':
                possible_values = self._get_possible_values()
                for val in possible_values:
                    if val != x[i]:
                        specializations.append(tuple(h_list[:i] + [val] + h_list[i+1:]))
        return specializations
    
    def _get_possible_values(self):
        """Get possible attribute values - simplified version"""
        return ['Sunny', 'Rainy', 'Overcast']  # Example - would need to be determined from data
    
    def _remove_duplicates(self, hypotheses):
        """Remove duplicate hypotheses"""
        seen = set()
        unique = []
        for h in hypotheses:
            t = tuple(h)
            if t not in seen:
                seen.add(t)
                unique.append(h)
        return unique
    
    def _generate_version_space(self, general, specific, n_features):
        """Generate all hypotheses in the version space"""
        version_space = []
        
        # Simplified version space generation
        # In practice, this would generate all hypotheses between general and specific boundaries
        
        if not general or not specific:
            return []
        
        # Add boundaries
        version_space.extend(general)
        version_space.extend(specific)
        
        # Return unique hypotheses
        return self._remove_duplicates(version_space)


class HypothesisTesting:
    """
    Statistical Hypothesis Testing Utilities
    """
    
    def __init__(self):
        pass
    
    def t_test(self, data: np.ndarray, mu0: float = 0, alternative: str = 'two-sided') -> dict:
        """
        Perform a one-sample t-test.
        
        Args:
            data: Array of sample observations
            mu0: Hypothesized population mean (default: 0)
            alternative: 'two-sided', 'less', or 'greater' (default: 'two-sided')
        
        Returns:
            Dictionary with test statistic, p-value, and conclusion
        """
        t_stat, p_value = stats.ttest_1samp(data, mu0)
        
        if alternative == 'less':
            p_value = p_value / 2 if t_stat < 0 else 1 - p_value / 2
        elif alternative == 'greater':
            p_value = p_value / 2 if t_stat > 0 else 1 - p_value / 2
        
        alpha = 0.05
        conclusion = "Reject H0" if p_value < alpha else "Fail to reject H0"
        
        return {
            'test_statistic': float(t_stat),
            'p_value': float(p_value),
            'conclusion': conclusion,
            'alpha': alpha
        }
    
    def two_sample_t_test(self, data1: np.ndarray, data2: np.ndarray, 
                          alternative: str = 'two-sided') -> dict:
        """
        Perform a two-sample t-test.
        
        Args:
            data1: First sample array
            data2: Second sample array
            alternative: 'two-sided', 'less', or 'greater'
        
        Returns:
            Dictionary with test results
        """
        t_stat, p_value = stats.ttest_ind(data1, data2)
        
        if alternative == 'less':
            p_value = p_value / 2 if t_stat < 0 else 1 - p_value / 2
        elif alternative == 'greater':
            p_value = p_value / 2 if t_stat > 0 else 1 - p_value / 2
        
        alpha = 0.05
        conclusion = "Reject H0" if p_value < alpha else "Fail to reject H0"
        
        return {
            'test_statistic': float(t_stat),
            'p_value': float(p_value),
            'conclusion': conclusion,
            'alpha': alpha
        }
    
    def chi_square_test(self, observed: np.ndarray, expected: Optional[np.ndarray] = None) -> dict:
        """
        Perform a chi-square test for goodness of fit or independence.
        
        Args:
            observed: Observed frequencies
            expected: Expected frequencies (optional)
        
        Returns:
            Dictionary with test results
        """
        chi2, p_value = stats.chisquare(observed, expected)
        
        alpha = 0.05
        conclusion = "Reject H0" if p_value < alpha else "Fail to reject H0"
        
        return {
            'chi2_statistic': float(chi2),
            'p_value': float(p_value),
            'conclusion': conclusion,
            'alpha': alpha
        }
    
    def normality_test(self, data: np.ndarray) -> dict:
        """
        Perform a Shapiro-Wilk test for normality.
        
        Args:
            data: Array of observations
        
        Returns:
            Dictionary with test results
        """
        if len(data) < 3 or len(data) > 5000:
            raise ValueError("Data must have between 3 and 5000 observations")
        
        stat, p_value = stats.shapiro(data)
        
        alpha = 0.05
        conclusion = "Data is not normally distributed" if p_value < alpha else "Data appears normally distributed"
        
        return {
            'test_statistic': float(stat),
            'p_value': float(p_value),
            'conclusion': conclusion,
            'alpha': alpha
        }

